\section{Combined affine-corner $\Module\,k$-finite consumer (iter-042)}
\label{sec:module_finite_HModule_prime_of_affine_iter042}

Iter-040 packaged the H${}^{>0}$ side of the affine-corner input as a class with consumer (Theorems~\ref{thm:Scheme_IsAffineHModuleVanishing}--\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}); iter-041 packaged the parallel H${}^0$ side (Theorems~\ref{thm:Scheme_IsAffineHModuleHomFinite}--\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}). Each consumer covers one degree side: the H${}^0$ consumer requires $i = 0$, the H${}^{>0}$ consumer requires $0 < i$. At every downstream call site (in particular, the iter-029 LES finite-length transport queued for iter-044+), the user must select between the two by case-split on $i$. Iter-042 folds both consumers into a single uniform statement covering all $i \ge 0$ under both class hypotheses, so the LES can chain through every degree without per-position case-splits.

\begin{theorem}[Combined affine-corner $\Module\,k$-finite consumer]
  \label{thm:Scheme_module_finite_HModule_prime_of_affine}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine}
  \uses{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing, thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\Opens\,(C.\mathtt{left}.\toTopCat)$. Assume \lstinline{IsAffineHModuleVanishing k C F} and \lstinline{IsAffineHModuleHomFinite k C F}. For any affine open $U$ of $C.\mathtt{left}$ and any $i \ge 0$, the cohomology group $\HModulePrime\,k\,F\,i\,U$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing, thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
  Case-split on \lstinline{Nat.eq_zero_or_pos i}. If $i = 0$, the iter-041 consumer (Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}) under \lstinline{IsAffineHModuleHomFinite k C F} produces $\Module.\mathrm{Finite}\,k\,(\HModulePrime\,k\,F\,0\,U)$. If $0 < i$, the iter-040 consumer (Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}) under \lstinline{IsAffineHModuleVanishing k C F} produces $\Module.\mathrm{Finite}\,k\,(\HModulePrime\,k\,F\,i\,U)$. Combined body: \lstinline{by rcases Nat.eq_zero_or_pos i with rfl | hi; \cdot exact module_finite_HModule'_zero_of_isAffineHModuleHomFinite k C F hU; \cdot exact module_finite_HModule'_of_isAffineHModuleVanishing k C F hU i hi}.
\end{proof}

\begin{theorem}[Curve specialisation]
  \label{thm:Scheme_module_finite_HModule_prime_of_affine_curve}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine_curve}
  \uses{thm:Scheme_module_finite_HModule_prime_of_affine}
  Direct curve specialisation of Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_affine} to $F := \toModuleKSheaf\,C$ for $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$. Under \lstinline{IsAffineHModuleVanishing k C (toModuleKSheaf C)} and \lstinline{IsAffineHModuleHomFinite k C (toModuleKSheaf C)}, for any affine open $U$ of $C.\mathtt{left}$ and any $i \ge 0$, the cohomology group $\HModulePrime\,k\,(\toModuleKSheaf\,C)\,i\,U$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_module_finite_HModule_prime_of_affine}
  \leanok
  One-line dot-notation wrapper: \lstinline{Scheme.module_finite_HModule'_of_affine k C (Scheme.toModuleKSheaf C) hU i}, mirroring the iter-030 / iter-035 / iter-036 / iter-037 / iter-039 \texttt{\_curve} patterns.
\end{proof}

\begin{remark}[Use in the LES finite-length transport, queued for iter-044+]
  After iter-042 the cover-evaluation chain consumes a single uniform $\Module\,k$-finite predicate at every degree. For an \lstinline{AffineCoverMVSquare} $S$ with corners $X_1, X_2, X_3$ affine and $X_4 = \top$, given \lstinline{IsAffineHModuleHomFinite k C F} and \lstinline{IsAffineHModuleVanishing k C F},
  \begin{enumerate}
    \item For each affine corner $X_j$ ($j = 1, 2, 3$) and each degree $i \ge 0$, $\HModulePrime^i(X_j)$ is $\Module\,k$-finite by Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_affine} (iter-042) — one class lookup, no per-degree case-split at the call site.
    \item The iter-029/030 LES specialised to $S$ then forces $\HModulePrime^i(X_4)$ to be a $\Module\,k$-finite extension of $\Module\,k$-finite pieces (queued for iter-044+ — bridges $\AddCommGrpCat$-side LES exactness to $k$-linear \lstinline{Function.Exact}).
    \item The iter-035 corner-bridge identifies $\HModulePrime^i(X_4)$ with $\HModule\,k\,F\,i$, and iter-037's transport carries the finiteness across — landing $\Module.\mathrm{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$, the genus carrier (Definition~\ref{def:genus}).
  \end{enumerate}
  Iter-043+ produces the carrier instances \lstinline{IsAffineHModuleHomFinite k C (toModuleKSheaf C)} (via Stein-factorization-derived $\Gamma(\Spec A, \struct C) \simeq A$ on affine corners of a finite-type $k$-scheme) and \lstinline{IsAffineHModuleVanishing k C (toModuleKSheaf C)} (via project-local Čech-vs-derived comparison + affine Čech vanishing).
\end{remark}

\section{Use in the project}
